import logging
import requests
from typing import List, Optional

logger = logging.getLogger(__name__)


class ApiClient:
    def __init__(self, base_url: str, api_keys: List[str]):
        if not api_keys:
            raise ValueError("At least one API key is required")
        self.base_url = base_url
        self._keys = list(api_keys)
        self._key_index = 0

    @property
    def current_key(self) -> str:
        return self._keys[self._key_index]

    def _rotate_key(self) -> bool:
        """Rotate to next key. Returns False if all keys exhausted."""
        next_idx = self._key_index + 1
        if next_idx >= len(self._keys):
            return False
        self._key_index = next_idx
        logger.info("Rotated to API key %d/%d", next_idx + 1, len(self._keys))
        return True

    def get(self, path: str) -> dict:
        while True:
            resp = requests.get(
                f"{self.base_url}{path}",
                headers={"Authorization": f"Bearer {self.current_key}"},
            )
            if resp.status_code == 401 and self._rotate_key():
                continue
            resp.raise_for_status()
            return resp.json()
